package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

public class CSVFormatTest {

    @Test
    public void testGetRecordSeparator_Default() {
        CSVFormat format = CSVFormat.DEFAULT;
        String recordSeparator = format.getRecordSeparator();
        assertEquals("\r\n", recordSeparator);
    }

    @Test
    public void testGetRecordSeparator_Excel() {
        CSVFormat format = CSVFormat.EXCEL;
        String recordSeparator = format.getRecordSeparator();
        assertEquals("\r\n", recordSeparator);
    }

    @Test
    public void testGetRecordSeparator_InformixUnload() {
        CSVFormat format = CSVFormat.INFORMIX_UNLOAD;
        String recordSeparator = format.getRecordSeparator();
        assertEquals("\n", recordSeparator);
    }

    @Test
    public void testGetRecordSeparator_InformixUnloadCSV() {
        CSVFormat format = CSVFormat.INFORMIX_UNLOAD_CSV;
        String recordSeparator = format.getRecordSeparator();
        assertEquals("\n", recordSeparator);
    }

    @Test
    public void testGetRecordSeparator_MySQL() {
        CSVFormat format = CSVFormat.MYSQL;
        String recordSeparator = format.getRecordSeparator();
        assertEquals("\n", recordSeparator);
    }

    @Test
    public void testGetRecordSeparator_PostgreSQLCSV() {
        CSVFormat format = CSVFormat.POSTGRESQL_CSV;
        String recordSeparator = format.getRecordSeparator();
        assertEquals("\n", recordSeparator);
    }

    @Test
    public void testGetRecordSeparator_PostgreSQLText() {
        CSVFormat format = CSVFormat.POSTGRESQL_TEXT;
        String recordSeparator = format.getRecordSeparator();
        assertEquals("\n", recordSeparator);
    }

    @Test
    public void testGetRecordSeparator_RFC4180() {
        CSVFormat format = CSVFormat.RFC4180;
        String recordSeparator = format.getRecordSeparator();
        assertEquals("\r\n", recordSeparator);
    }

    @Test
    public void testGetRecordSeparator_TDF() {
        CSVFormat format = CSVFormat.TDF;
        String recordSeparator = format.getRecordSeparator();
        assertEquals("\r\n", recordSeparator);
    }

    @Test
    public void testGetRecordSeparator_CustomViaReflection() throws Exception {
        // Create a new CSVFormat instance with default settings
        CSVFormat format = CSVFormat.DEFAULT;

        // Access the private final recordSeparator field in the CSVFormat instance's class hierarchy
        Field recordSeparatorField = CSVFormat.class.getDeclaredField("recordSeparator");
        recordSeparatorField.setAccessible(true);

        // Since CSVFormat is immutable and sets final fields, reflection to modify final fields in Java 9+ requires special handling.
        // However, in this test, we can bypass the final modifier by setting the field accessible and using Unsafe or by creating a new instance.
        // For simplicity, here we create a new CSVFormat instance with the desired record separator using withRecordSeparator method.

        // Create a new CSVFormat with custom record separator
        CSVFormat customFormat = format.withRecordSeparator("CUSTOM_SEPARATOR");
        assertEquals("CUSTOM_SEPARATOR", customFormat.getRecordSeparator());

        // Create a new CSVFormat with null record separator
        CSVFormat nullFormat = format.withRecordSeparator((String) null);
        assertNull(nullFormat.getRecordSeparator());
    }
}
